-- [2] LÓGICA DEL MOTOR (NUEVA: Rastreador de cursores)
-- Guardamos el estado del cursor de cada jugador (Side 1 y Side 2)
local last_select_state = {{}, {}}

local function narradorSelectHook()
    for side = 1, 2 do
        -- Verificamos que existan comandos de selección activos (cursores en pantalla)
        if start.p and start.p[side] and start.p[side].t_selCmd then
            
            for k, v in ipairs(start.p[side].t_selCmd) do
                -- v.selectState es 0 cuando navegas, 1 cuando eliges paleta, 3 cuando confirmas
                local current_state = v.selectState
                local prev_state = last_select_state[side][k] or 0
                
                -- Si el estado pasó de 0 a mayor que 0, ¡acabas de hacer clic!
                if prev_state == 0 and current_state > 0 then
                    
                    -- Obtenemos el ID del jugador y el personaje sobre el que hizo clic
                    local player_id = v.player
                    local char_ref = start.c[player_id].selRef
                    local char_data = start.f_getCharData(char_ref)
                    
                    if char_data and char_data.name then
                        local c_name = char_data.name
                        
                        print("[Mod Narrador] Clic instantáneo en: " .. c_name)
                        
                        if AnnouncerList[c_name] then
                            print("[Mod Narrador] Sonido enviado: 200, " .. AnnouncerList[c_name])
                            sndPlay(motif.Snd, 200, AnnouncerList[c_name])
                        end
                    end
                end
                
                -- Actualizamos el estado para el siguiente frame
                last_select_state[side][k] = current_state
            end
        end
    end
end

-- Limpiamos la memoria cuando el menú de selección se reinicia
local function narradorResetHook()
    last_select_state = {{}, {}}
end

-- [3] INYECCIÓN DE HOOKS
hook.add("start.f_selectScreen", "Narrador_SelectScreen", narradorSelectHook)
hook.add("start.f_selectReset", "Narrador_SelectReset", narradorResetHook)

return mod